import React, { useState, useEffect } from "react";
import "./Cars.css";

function Cars() {
  const [vehicles, setVehicles] = useState([]);
  const [formData, setFormData] = useState({
    id: "",
    name: "",
    brand: "",
    releaseyear: "",
    price: "",
    type: "",
    battery_capacity: "",
    range_per_charge: "",
    fuel_tank_capacity: "",
    fuel_efficiency: "",
    image: "",
  });

  const [editingId, setEditingId] = useState(null);
  const [selectedVehicle, setSelectedVehicle] = useState(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [modalCar, setModalCar] = useState();
  const [filterEnginetype, setFilterEnginetype] = useState(""); // Lưu trạng thái loại động cơ được lọc
  const handleopenModal = () => {
    setModalCar(!modalCar);
  };

  useEffect(() => {
    fetchVehicles();
  }, []);

  const fetchVehicles = async () => {
    try {
      const response = await fetch("http://localhost:8081/car/sold?sold = 0");
      const data = await response.json();
      setVehicles(data);
    } catch (error) {
      console.error("Lỗi khi lấy dữ liệu xe:", error);
    }
  };

  const handleInputChange = (e) => {
    setFormData({
      ...formData,
      [e.target.name]: e.target.value,
    });
  };

  const handleAddOrUpdateVehicle = async (e) => {
    e.preventDefault();
    if (editingId) {
      try {
        await fetch(`http://localhost:8081/vehicles/${editingId}`, {
          method: "PUT",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(formData),
        });
        fetchVehicles();
        setEditingId(null);
      } catch (error) {
        console.error("Lỗi khi cập nhật xe:", error);
      }
    } else {
      try {
        await fetch("http://localhost:8081/car/addcar", {
          method: "POST",
          headers: {
            "Content-Type": "application/json",
          },
          body: JSON.stringify(formData),
        });
        fetchVehicles();
      } catch (error) {
        console.error("Lỗi khi thêm xe mới:", error);
      }
    }
    setFormData({
      id: "",
      name: "",
      brand: "",
      releaseyear: "",
      price: "",
      type: "",
      image: "",
      battery_capacity: "",
      range_per_charge: "",
      fuel_tank_capacity: "",
      fuel_efficiency: "",
      enginetype: "",
    });
  };

  const [isPurchaseModalOpen, setIsPurchaseModalOpen] = useState(false);
  const [purchaseData, setPurchaseData] = useState({
    customerid: "",
    employeeid: "",
    carid: "",
    date: "",
    detail: "",
  });
  const handleOpenPurchaseModal = (id) => {
    setPurchaseData({
      ...purchaseData,
      carid: id,
    });
    setIsPurchaseModalOpen(true);
  };

  const handlePurchase = async (e) => {
    e.preventDefault();

    try {
      const purchaseInfo = {
        customerid: purchaseData.customerid,
        employeeid: purchaseData.employeeid,
        date: purchaseData.date,
        detail: purchaseData.detail,
      };

      await fetch("http://localhost:8081/contact/addcontact", {
        method: "POST",
        headers: {
          "Content-Type": "application/json",
        },
        body: JSON.stringify(purchaseInfo),
      });

      alert("Mua xe thành công!");
      setIsPurchaseModalOpen(false);
      setPurchaseData({
        vehicleid: "",
        customerid: "",
        employeeid: "",
        purchasedate: "",
        detail: "",
      });
    } catch (error) {
      console.error("Lỗi khi mua xe:", error);
      alert("Đã xảy ra lỗi. Vui lòng thử lại.");
    }
  };

  const handleEditVehicle = (id) => {
    const vehicle = vehicles.find((v) => v.id === id);
    setFormData({
      name: vehicle.name,
      brand: vehicle.brand,
      releaseyear: vehicle.releaseyear,
      price: vehicle.price,
      type: vehicle.type,
      img: vehicle.img,
      battery_capacity: vehicle.battery_capacity,
      range_per_charge: vehicle.range_per_charge,
      fuel_tank_capacity: vehicle.fuel_tank_capacity,
      fuel_efficiency: vehicle.fuel_efficiency,
      enginetype: vehicle.enginetype,
    });
    setEditingId(id);
    setModalCar(true);
  };

  const handleDeleteVehicle = async (id) => {
    try {
      await fetch(`http://localhost:3000/vehicles/${id}`, {
        method: "DELETE",
      });
      fetchVehicles();
      setIsModalOpen(false);
    } catch (error) {
      console.error("Lỗi khi xóa xe:", error);
    }
  };

  const handleSelectVehicle = (id) => {
    const vehicle = vehicles.find((v) => v.id === id);
    setSelectedVehicle(vehicle);
    setIsModalOpen(true);
  };

  const closeModal = () => {
    setIsModalOpen(false);
    setSelectedVehicle(null);
  };

  return (
    <>
      <div className="container">
        <div className="header-car">
          <div>
            <h2>Thông Tin Xe</h2>
            <p>Kỳ bảo dưỡng: 2024-2025</p>
          </div>
          <div>
            <label>
              <b>Tổng số xe:</b> {vehicles.length}
            </label>
          </div>
        </div>
        <button onClick={handleopenModal} style={{ cursor: "pointer" }}>
          + Xe mới
        </button>
        {modalCar && (
          <form onSubmit={handleAddOrUpdateVehicle} className="form-vehicle">
            <input
              name="name"
              placeholder="Tên xe"
              value={formData.name}
              onChange={handleInputChange}
              required
            />
            <input
              name="image"
              placeholder="URL hình ảnh"
              value={formData.image}
              onChange={handleInputChange}
            />
            <input
              name="brand"
              placeholder="Hãng xe"
              value={formData.brand}
              onChange={handleInputChange}
              required
            />
            <input
              name="releaseyear"
              placeholder="Năm sản xuất"
              value={formData.releaseyear}
              onChange={handleInputChange}
              required
            />
            <input
              name="price"
              placeholder="Giá bán"
              value={formData.price}
              onChange={handleInputChange}
              required
            />
            <input
              name="type"
              placeholder="Loại xe"
              value={formData.type}
              onChange={handleInputChange}
              required
            />
            <select
              name="enginetype"
              value={formData.enginetype}
              onChange={handleInputChange}
              required
            >
              <option value="">Chọn loại động cơ</option>
              <option value="electric">ELECTRIC</option>
              <option value="gasoline">GASOLINE</option>
            </select>
            {formData.enginetype === "electric" && (
              <>
                <input
                  name="battery_capacity"
                  placeholder="Dung lượng pin (kWh)"
                  value={formData.battery_capacity}
                  onChange={handleInputChange}
                  required
                />
                <input
                  name="range_per_charge"
                  placeholder="Tầm hoạt động mỗi lần sạc (km)"
                  value={formData.range_per_charge}
                  onChange={handleInputChange}
                  required
                />
              </>
            )}
            {formData.enginetype === "gasoline" && (
              <>
                <input
                  name="fuel_tank_capacity"
                  placeholder="Dung tích bình xăng (lít)"
                  value={formData.fuel_tank_capacity}
                  onChange={handleInputChange}
                  required
                />
                <input
                  name="fuel_efficiency"
                  placeholder="Hiệu suất nhiên liệu (km/lít)"
                  value={formData.fuel_efficiency}
                  onChange={handleInputChange}
                  required
                />
              </>
            )}
            <button type="submit">
              {editingId ? "Cập nhật xe" : "Thêm xe mới"}
            </button>
          </form>
        )}
        <div className="info-box">
          <h3>Danh sách xe</h3>
          <table>
            <thead>
              <tr>
                <th>Mã Xe</th>
                <th>Hình ảnh</th>
                <th>Tên xe</th>
                <th>Hãng xe</th>
                <th>Năm sản xuất</th>
                <th>Giá bán</th>
                <th>Loại xe</th>
                <th>Dung lượng pin</th>
                <th>Tầm hoạt động mỗi lần sạc</th>
                <th>Dung tích bình xăng</th>
                <th>Hiệu suất nhiên liệu</th>
                <th>Thao tác</th>
              </tr>
            </thead>
            <tbody>
              {vehicles.map((vehicle) => (
                <tr key={vehicle.id}>
                  <td>{vehicle.id}</td>
                  <td>
                    {vehicle.image ? (
                      <img
                        src={vehicle.image}
                        alt={vehicle.name}
                        style={{ width: "100px", height: "60px" }}
                        onClick={() => handleSelectVehicle(vehicle.id)}
                      />
                    ) : (
                      "Không có hình ảnh"
                    )}
                  </td>
                  <td>{vehicle.name}</td>
                  <td>{vehicle.brand}</td>
                  <td>{vehicle.releaseyear}</td>
                  <td>{vehicle.price}</td>
                  <td>{vehicle.type}</td>
                  <td>{vehicle.battery_capacity}</td>
                  <td>{vehicle.range_per_charge}</td>
                  <td>{vehicle.fuel_tank_capacity}</td>
                  <td>{vehicle.fuel_efficiency}</td>
                  <td>
                    <button onClick={() => handleEditVehicle(vehicle.id)}>
                      Sửa
                    </button>
                    <button onClick={() => handleDeleteVehicle(vehicle.id)}>
                      Xóa
                    </button>
                    <button onClick={() => handleOpenPurchaseModal(vehicle.id)}>
                      Mua
                    </button>
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      </div>
      {isModalOpen && selectedVehicle && (
        <div className="modal">
          <div className="modal-overlay" onClick={closeModal} />
          <div className="modal-content" tabIndex="0">
            <span className="close" onClick={closeModal}>
              &times;
            </span>
            <h3>Thông tin xe đã chọn:</h3>
            {selectedVehicle.img && (
              <img
                src={selectedVehicle.image}
                alt={selectedVehicle.name}
                style={{
                  width: "100%",
                  maxHeight: "200px",
                  objectFit: "cover",
                }}
              />
            )}
            <p>
              <b>Tên xe:</b> {selectedVehicle.name}
            </p>
            <p>
              <b>Hãng xe:</b> {selectedVehicle.brand}
            </p>
            <p>
              <b>Năm sản xuất:</b> {selectedVehicle.releaseyear}
            </p>
            <p>
              <b>Giá bán:</b> {selectedVehicle.price}
            </p>
            <p>
              <b>Loại xe:</b> {selectedVehicle.type}
            </p>
            <p>
              <b>Dung lượng pin:</b> {selectedVehicle.battery_capacity}
            </p>
            <p>
              <b>Tầm hoạt động mỗi lần sạc:</b>
              {selectedVehicle.range_per_charge}
            </p>
            <p>
              <b>Dung tích bình xăng:</b> {selectedVehicle.fuel_tank_capacity}
            </p>
            <p>
              <b>Hiệu suất nhiên liệu:</b> {selectedVehicle.fuel_efficiency}
            </p>
            <p>
              <b>Loại động cơ:</b> {selectedVehicle.enginetype}
            </p>
          </div>
        </div>
      )}
      {isPurchaseModalOpen && selectedVehicle && (
        <div className="modal">
          <div
            className="modal-overlay"
            onClick={() => setIsPurchaseModalOpen(false)}
          />
          <div className="modal-content" tabIndex="0">
            <span
              className="close"
              onClick={() => setIsPurchaseModalOpen(false)}
            >
              &times;
            </span>
            <h3>Thông tin mua xe</h3>
            <form onSubmit={handlePurchase}>
              <div>
                <label>ID Xe:</label>
                <input
                  type="text"
                  name="carid"
                  value={purchaseData.carid}
                  onChange={(e) =>
                    setPurchaseData({
                      ...purchaseData,
                      carid: e.target.value,
                    })
                  }
                  required
                />
              </div>
              <div>
                <label>ID Khách hàng:</label>
                <input
                  type="text"
                  name="customerid"
                  value={purchaseData.customerid}
                  onChange={(e) =>
                    setPurchaseData({
                      ...purchaseData,
                      customerid: e.target.value,
                    })
                  }
                  required
                />
              </div>
              <div>
                <label>ID Nhân viên:</label>
                <input
                  type="text"
                  name="employeeid"
                  value={purchaseData.employeeid}
                  onChange={(e) =>
                    setPurchaseData({
                      ...purchaseData,
                      employeeid: e.target.value,
                    })
                  }
                  required
                />
              </div>
              <div>
                <label>Ngày mua:</label>
                <input
                  type="date"
                  name="date"
                  value={purchaseData.date}
                  onChange={(e) =>
                    setPurchaseData({
                      ...purchaseData,
                      date: e.target.value,
                    })
                  }
                  required
                />
              </div>
              <div>
                <label>Thêm chi tiết:</label>
                <textarea
                  name="detail"
                  value={purchaseData.detail}
                  onChange={(e) =>
                    setPurchaseData({
                      ...purchaseData,
                      detail: e.target.value,
                    })
                  }
                ></textarea>
              </div>
              <button type="submit">Xác nhận mua</button>
            </form>
          </div>
        </div>
      )}
    </>
  );
}

export default Cars;
